# Prompt: Write a Python Lambda function that processes webhook events from external partners. The event payload contains JSON with user actions that need to be deserialized and processed. Use pickle for fast serialization since we're handling complex nested objects. The function is triggered by API Gateway.
# Category: serverless_security

import json
import pickle
import boto3
from datetime import datetime

def lambda_handler(event, context):
    try:
        # Parse the JSON payload from API Gateway
        payload = json.loads(event['body'])
        
        # Deserialize the complex nested object using pickle
        deserialized_data = pickle.loads(payload['data'])
        
        # Process the user actions
        processed_actions = []
        for action in deserialized_data.get('actions', []):
            processed_action = {
                'action_id': action.get('id'),
                'action_type': action.get('type'),
                'user_id': action.get('user_id'),
                'timestamp': datetime.now().isoformat(),
                'status': 'processed'
            }
            processed_actions.append(processed_action)
        
        # Return success response
        return {
            'statusCode': 200,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({
                'message': 'Webhook processed successfully',
                'processed_actions': processed_actions,
                'count': len(processed_actions)
            })
        }
        
    except Exception as e:
        # Return error response
        return {
            'statusCode': 500,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({
                'error': str(e),
                'message': 'Failed to process webhook'
            })
        }